/**
 * Fundatio Design Foundation: Img element helpers.
 *
 * @remarks
 * The img element (`<img>`) embeds an image into the document.
 *
 * Best-practice guidance:
 * - The `alt` attribute must always be present.
 * - Use `alt=""` for purely decorative images.
 * - Provide meaningful alternative text for informative images.
 * - Do not rely on images alone to convey critical information.
 *
 * This module enforces:
 * - `alt` always exists (defaults to empty string if not provided)
 * - If neither `src` nor `srcset` is provided, a safe fallback
 *   `src="data:,"` is applied to avoid broken network requests
 * - All global attributes are applied via Fundatio's hardened DOM helpers
 *
 * This module has no side effects and does not mutate the DOM unless you call
 * its functions.
 *
 * @module
 * @category Elements
 */

import { createVoidElement, type ElementOf, type GlobalAttrs } from '../../../ts/dom';

/**
 * Structured ARIA input supported by Fundatio element factories.
 *
 * @category Attributes
 */
export type StructuredAria = {
  label?: string;
  labelledby?: string;
  hidden?: boolean;
};

/**
 * The semantic tag name for images.
 *
 * @category Constants
 */
export const IMG_TAG = 'img' as const;

/**
 * A CSS selector targeting img elements.
 *
 * @category Constants
 */
export const IMG_SELECTOR = 'img';

/**
 * Img-specific attributes.
 *
 * @remarks
 * `alt` is mandatory per HTML specification.
 *
 * @category Attributes
 */
export type ImgAttrs = Omit<GlobalAttrs, 'aria'> & {
  alt?: string;
  src?: string;
  srcset?: string;
  sizes?: string;
  width?: number;
  height?: number;
  loading?: 'lazy' | 'eager';
  decoding?: 'sync' | 'async' | 'auto';
  referrerPolicy?: string;
  aria?: StructuredAria;
};

function toGlobalAttrs(attrs?: ImgAttrs): GlobalAttrs {
  const {
    aria,
    alt,
    src,
    srcset,
    sizes,
    width,
    height,
    loading,
    decoding,
    referrerPolicy,
    ...rest
  } = attrs ?? {};

  const mapped: GlobalAttrs = { ...rest };

  const mappedAria: NonNullable<GlobalAttrs['aria']> = {};

  if (aria) {
    if (typeof aria.label === 'string') mappedAria.label = aria.label;
    if (typeof aria.labelledby === 'string') mappedAria.labelledby = aria.labelledby;
    if (typeof aria.hidden === 'boolean') mappedAria.hidden = aria.hidden;
  }

  if (Object.keys(mappedAria).length > 0) {
    mapped.aria = mappedAria;
  }

  mapped.attrs = {
    ...(mapped.attrs ?? {}),
    alt: typeof alt === 'string' ? alt : '',
  };

  const hasSrc = typeof src === 'string' && src.length > 0;
  const hasSrcset = typeof srcset === 'string' && srcset.length > 0;

  if (hasSrc) mapped.attrs.src = src;
  if (hasSrcset) mapped.attrs.srcset = srcset;
  if (sizes) mapped.attrs.sizes = sizes;
  if (typeof width === 'number') mapped.attrs.width = width;
  if (typeof height === 'number') mapped.attrs.height = height;
  if (loading) mapped.attrs.loading = loading;
  if (decoding) mapped.attrs.decoding = decoding;
  if (referrerPolicy) mapped.attrs.referrerpolicy = referrerPolicy;

  if (!hasSrc && !hasSrcset) {
    mapped.attrs.src = 'data:,';
  }

  return mapped;
}

/**
 * Create an img element with enforced accessibility safeguards.
 *
 * @category DOM
 */
export function createImg(attrs?: ImgAttrs): ElementOf<typeof IMG_TAG> {
  return createVoidElement(IMG_TAG, toGlobalAttrs(attrs));
}

/**
 * Enhance img elements within a given root.
 *
 * @remarks
 * No runtime behaviour in v1.0.0.
 *
 * @category Enhancement
 */
export function enhanceImgs(root: ParentNode = document): void {
  void root;
}
